def word_break(s, word_dict):
    words = set(word_dict)
    n = len(s)

    def helper(i):
        if i == n:
            return True
        for j in range(i + 1, n + 1):
            if s[i:j] in words and helper(j):
                return True
        return False

    return helper(0)

def word_break(s, word_dict):
    words = set(word_dict)
    n = len(s)
    dp = [False] * (n + 1)
    dp[0] = True
    for i in range(1, n + 1):
        for j in range(i):
            if dp[j] and s[j:i] in words:
                dp[i] = True
                break
    return dp[n]
